// --- Helpers ---

interface InternalVM {
  currentMode: PublishMode
  internalData: {
    content: string
    attachments: unknown[]
    externalLink: string
    coverImage: string
    summary: string
  }
  handleModeChange: (mode: string | number | boolean | undefined) => void
  handleContentChange: (value: string) => void
  handleLinkFieldChange: (field: 'externalLink' | 'coverImage' | 'summary', value: string) => void
}

function createWrapper(props: Record<string, unknown> = {}) {
  return mount(ContentPublisher, {
    props: {
      modelValue: { publishType: 'richtext' as const } satisfies ContentPublishData,
      ...props,
    },
    global: {
      plugins: [ElementPlus],
    },
  })
}

function getExposed(wrapper: ReturnType<typeof mount>): ContentPublisherExpose {
  return wrapper.vm as unknown as ContentPublisherExpose
}

function getVM(wrapper: ReturnType<typeof mount>): InternalVM {
  return wrapper.vm as unknown as InternalVM
}

/** Switch mode by calling internal handler (reliable in test env) */
async function switchMode(wrapper: ReturnType<typeof mount>, mode: PublishMode) {
  getVM(wrapper).handleModeChange(mode)
  await flushPromises()
}

// ============================================================
// AC1: 发布方式切换
// ============================================================

describe('AC1: 发布方式切换', () => {
  // --- Core Scenarios ---

  test('4.5-UNIT-001: 默认选中"图文编辑"模式', () => {
    // Priority: P0
    const wrapper = createWrapper()
    expect(getVM(wrapper).currentMode).toBe('richtext')
    // Verify radio is visually checked
    const radios = wrapper.findAll('.el-radio')
    const checked = radios.find(r => r.classes().includes('is-checked'))
    expect(checked?.text()).toContain('图文编辑')
  })

  test('4.5-UNIT-002: Radio Group 显示三个选项：图文编辑、附件上传、外部链接', () => {
    // Priority: P1
    const wrapper = createWrapper()
    const radios = wrapper.findAll('.el-radio')
    expect(radios.length).toBe(3)
    expect(radios[0].text()).toContain('图文编辑')
    expect(radios[1].text()).toContain('附件上传')
    expect(radios[2].text()).toContain('外部链接')
  })

  test('4.5-UNIT-003: 切换模式时动态渲染对应输入组件', async () => {
    // Priority: P1
    const wrapper = createWrapper()

    // Default: richtext mode
    expect(getVM(wrapper).currentMode).toBe('richtext')
    expect(wrapper.findComponent({ name: 'RichTextEditor' }).exists()).toBe(true)

    // Switch to attachment
    await switchMode(wrapper, 'attachment')
    expect(getVM(wrapper).currentMode).toBe('attachment')
    expect(wrapper.findComponent({ name: 'AttachmentUpload' }).exists()).toBe(true)

    // Switch to link
    await switchMode(wrapper, 'link')
    expect(getVM(wrapper).currentMode).toBe('link')
    expect(wrapper.find('.el-form').exists()).toBe(true)
  })

  test('4.5-UNIT-004: 切换模式时其他模式已输入数据不被清空', async () => {
    // Priority: P1
    const wrapper = createWrapper()

    // Set richtext content
    getVM(wrapper).handleContentChange('<p>Hello World</p>')
    await flushPromises()

    // Switch to attachment then back
    await switchMode(wrapper, 'attachment')
    await switchMode(wrapper, 'richtext')

    // Content should be preserved in internal data
    expect(getVM(wrapper).internalData.content).toBe('<p>Hello World</p>')
    // Emitted value should have the content
    const emitted = wrapper.emitted('update:modelValue') as ContentPublishData[][]
    const lastEmit = emitted[emitted.length - 1][0]
    expect(lastEmit.content).toBe('<p>Hello World</p>')
  })

  test('4.5-UNIT-005: 提交时仅提交当前选中模式的数据', async () => {
    // Priority: P1
    const wrapper = createWrapper()

    // Fill richtext
    getVM(wrapper).handleContentChange('<p>Rich content</p>')
    await flushPromises()

    // Fill link
    await switchMode(wrapper, 'link')
    getVM(wrapper).handleLinkFieldChange('externalLink', 'https://example.com')
    await flushPromises()

    const emitted = wrapper.emitted('update:modelValue') as ContentPublishData[][]
    const lastEmit = emitted[emitted.length - 1][0]
    expect(lastEmit.publishType).toBe('link')
    expect(lastEmit.externalLink).toBe('https://example.com')
    expect(lastEmit.content).toBeUndefined()
  })

  test('4.5-UNIT-006: 未选择任何模式时阻止提交并显示"请选择发布方式"', async () => {
    // Priority: P1
    // The component always has a default mode. Testing empty richtext content.
    const wrapper = createWrapper()
    const { validate } = getExposed(wrapper)
    const result = await validate()
    expect(result).toBe(false)
  })

  test('4.5-UNIT-007: 当前模式无有效内容时显示"请填写{模式名}内容"', async () => {
    // Priority: P1
    const wrapper = createWrapper()
    const { validate } = getExposed(wrapper)
    await validate()
    await flushPromises()

    const errorEl = wrapper.find('.content-publisher__error')
    expect(errorEl.exists()).toBe(true)
    expect(errorEl.text()).toContain('请输入图文内容')
  })

  // --- Blind Spot Scenarios ---

  test('[BLIND-SPOT] 4.5-BLIND-FLOW-001: 快速连续切换模式（5次以上）数据保持一致', async () => {
    // Category: FLOW, Priority: P1
    const wrapper = createWrapper()

    // Set richtext content
    getVM(wrapper).handleContentChange('<p>Preserved</p>')
    await flushPromises()

    // Quick switch: richtext → attachment → link → richtext → attachment → link
    const modes: PublishMode[] = ['attachment', 'link', 'richtext', 'attachment', 'link', 'richtext']
    for (const mode of modes) {
      await switchMode(wrapper, mode)
    }

    // Back to richtext — content preserved
    expect(getVM(wrapper).internalData.content).toBe('<p>Preserved</p>')
    const emitted = wrapper.emitted('update:modelValue') as ContentPublishData[][]
    const lastEmit = emitted[emitted.length - 1][0]
    expect(lastEmit.content).toBe('<p>Preserved</p>')
  })
})

