describe('AC5: 外部链接协议限制', () => {
  async function testUrlProtocol(url: string, shouldPass: boolean) {
    const wrapper = createWrapper()
    await switchMode(wrapper, 'link')
    getVM(wrapper).handleLinkFieldChange('externalLink', url)
    await flushPromises()

    const { validate } = getExposed(wrapper)
    const result = await validate()
    expect(result).toBe(shouldPass)
  }

  test('4.5-UNIT-024: http:// 开头的 URL 通过验证', async () => {
    await testUrlProtocol('http://example.com', true)
  })

  test('4.5-UNIT-025: https:// 开头的 URL 通过验证', async () => {
    await testUrlProtocol('https://example.com', true)
  })

  test('4.5-UNIT-026: ftp:// URL 被拒绝', async () => {
    await testUrlProtocol('ftp://files.example.com/doc.pdf', false)
  })

  test('4.5-UNIT-027: file:// URL 被拒绝', async () => {
    await testUrlProtocol('file:///etc/passwd', false)
  })

  test('4.5-UNIT-028: mailto: URL 被拒绝', async () => {
    await testUrlProtocol('mailto:admin@example.com', false)
  })
})

